"use strict";const fs=require("fs");const path=require("path");const{execSync,execFileSync,spawn}=require("child_process");const PROJECT_ROOT=path.resolve(__dirname,"../..");const BRIDGE_DIR=path.join(PROJECT_ROOT,".claude/gemini-bridge");const PENDING_FILE=path.join(BRIDGE_DIR,"pending-files.txt");const REVIEWS_DIR=path.join(BRIDGE_DIR,"reviews");const STATE_FILE=path.join(BRIDGE_DIR,"gemini-state.json");const PID_FILE=path.join(BRIDGE_DIR,"daemon.pid");const LOG_FILE=path.join(BRIDGE_DIR,"daemon.log");const BRIDGE_JS=path.join(__dirname,"gemini-bridge.js");const DEBOUNCE_MS=5e3;const DAILY_LIMIT=100;const POLL_INTERVAL=2e3;const MAX_FILES_PER_REVIEW=20;function log(msg){const line=`[${(new Date).toISOString()}] ${msg}`;try{fs.appendFileSync(LOG_FILE,line+"\n","utf8")}catch(_){}}function ensureDirs(){[BRIDGE_DIR,REVIEWS_DIR].forEach(d=>{if(!fs.existsSync(d))fs.mkdirSync(d,{recursive:true})})}function loadState(){try{if(!fs.existsSync(STATE_FILE))return initState();const raw=fs.readFileSync(STATE_FILE,"utf8");const s=JSON.parse(raw);const today=(new Date).toISOString().slice(0,10);if(s.date!==today){s.date=today;s.callCount=0}return s}catch(_){return initState()}}function initState(){return{date:(new Date).toISOString().slice(0,10),callCount:0,pendingReviews:[]}}function readPendingFiles(){try{if(!fs.existsSync(PENDING_FILE))return[];const content=fs.readFileSync(PENDING_FILE,"utf8").trim();if(!content)return[];return[...new Set(content.split("\n").filter(Boolean))]}catch(_){return[]}}function clearPendingFiles(){try{fs.writeFileSync(PENDING_FILE,"","utf8")}catch(_){}}function checkExistingDaemon(){let pid;try{if(!fs.existsSync(PID_FILE))return false;pid=parseInt(fs.readFileSync(PID_FILE,"utf8").trim(),10);if(isNaN(pid))return false;if(pid===process.pid)return false;process.kill(pid,0);log(`Another daemon is already running (PID: ${pid}). Exiting.`);return true}catch(e){if(e.code==="ESRCH"){try{fs.unlinkSync(PID_FILE)}catch(_){}}if(e.code==="EPERM"){log(`Another daemon is running (PID: ${pid}, EPERM). Exiting.`);return true}return false}}function writePidFile(){try{fs.writeFileSync(PID_FILE,String(process.pid),"utf8")}catch(_){}}function cleanupPidFile(){try{if(fs.existsSync(PID_FILE)){const pid=parseInt(fs.readFileSync(PID_FILE,"utf8").trim(),10);if(pid===process.pid)fs.unlinkSync(PID_FILE)}}catch(_){}}function writePendingFiles(files){try{fs.writeFileSync(PENDING_FILE,files.join("\n")+"\n","utf8")}catch(_){}}function runGeminiReview(files){return new Promise(resolve=>{const state=loadState();if(state.callCount>=DAILY_LIMIT){log(`Daily limit reached (${state.callCount}/${DAILY_LIMIT}). Skipping.`);resolve({success:false,reason:"daily_limit"});return}const filesToReview=files.slice(0,MAX_FILES_PER_REVIEW);const remainingFiles=files.slice(MAX_FILES_PER_REVIEW);if(remainingFiles.length>0){log(`Batch limited: reviewing ${filesToReview.length}, deferring ${remainingFiles.length} file(s).`);writePendingFiles(remainingFiles)}log(`Starting Gemini review for ${filesToReview.length} file(s): ${filesToReview.join(", ")}`);const cleanEnv={...process.env};delete cleanEnv.CLAUDE_SANDBOX;delete cleanEnv.SANDBOX_MODE;const child=spawn("node",[BRIDGE_JS,"review",...filesToReview],{cwd:PROJECT_ROOT,stdio:["ignore","pipe","pipe"],env:cleanEnv});let stdout="";let stderr="";child.stdout.on("data",chunk=>{stdout+=chunk});child.stderr.on("data",chunk=>{stderr+=chunk});const timeout=setTimeout(()=>{log("Review timed out (150s). Killing child process.");child.kill("SIGKILL")},15e4);child.on("close",code=>{clearTimeout(timeout);if(code===0){log("Review completed successfully.");if(stdout.trim())log(`Output: ${stdout.trim().slice(0,500)}`);resolve({success:true,output:stdout.trim(),remaining:remainingFiles})}else{const errMsg=stderr.trim()||`Exit code ${code}`;log(`Review failed: ${errMsg.slice(0,300)}`);resolve({success:false,reason:errMsg.slice(0,300),remaining:remainingFiles})}});child.on("error",e=>{clearTimeout(timeout);log(`Review spawn error: ${e.message}`);resolve({success:false,reason:e.message})})})}function notifyIfCritical(reviewResult){if(!reviewResult||!reviewResult.success)return;try{const reviewFiles=fs.readdirSync(REVIEWS_DIR).filter(f=>f.endsWith(".json")).sort().reverse();if(reviewFiles.length===0)return;const latest=JSON.parse(fs.readFileSync(path.join(REVIEWS_DIR,reviewFiles[0]),"utf8"));if(latest.status==="completed"&&latest.needsAttention){const criticalCount=(latest.issues||[]).filter(i=>i.severity==="critical").length;const msg=criticalCount>0?`Gemini: ${criticalCount}건의 critical 이슈 발견!`:`Gemini: 코드 리뷰 주의 필요`;try{const safeMsg=msg.replace(/["\\]/g,"");execFileSync("osascript",["-e",`display notification "${safeMsg}" with title "Claude Code - KiiPS" sound name "Basso"`],{timeout:5e3,stdio:"ignore"})}catch(_){}log(`Notification sent: ${msg}`)}}catch(_){}}let debounceTimer=null;let lastMtime=0;function onPendingFileChanged(){clearTimeout(debounceTimer);debounceTimer=setTimeout(async()=>{const files=readPendingFiles();if(files.length===0){log("Pending files empty, skipping.");return}log(`Debounce triggered. Processing ${files.length} file(s)...`);const result=await runGeminiReview(files);if(result.success){if(!result.remaining||result.remaining.length===0){clearPendingFiles()}notifyIfCritical(result)}else if(result.reason==="daily_limit"){clearPendingFiles()}},DEBOUNCE_MS)}function startWatcher(){ensureDirs();if(!fs.existsSync(PENDING_FILE)){fs.writeFileSync(PENDING_FILE,"","utf8")}let watcher=null;try{watcher=fs.watch(PENDING_FILE,eventType=>{if(eventType==="change"){try{const stat=fs.statSync(PENDING_FILE);if(stat.size===0)return;if(stat.mtimeMs===lastMtime)return;lastMtime=stat.mtimeMs}catch(_){return}onPendingFileChanged()}});log("fs.watch started on pending-files.txt")}catch(e){log(`fs.watch failed (${e.message}), falling back to polling.`)}const pollTimer=setInterval(()=>{try{if(!fs.existsSync(PENDING_FILE))return;const stat=fs.statSync(PENDING_FILE);if(stat.size===0)return;if(stat.mtimeMs===lastMtime)return;lastMtime=stat.mtimeMs;onPendingFileChanged()}catch(_){}},POLL_INTERVAL);return{watcher:watcher,pollTimer:pollTimer}}function shutdown(signal){log(`Received ${signal}. Shutting down gracefully...`);clearTimeout(debounceTimer);cleanupPidFile();process.exit(0)}process.on("SIGINT",()=>shutdown("SIGINT"));process.on("SIGTERM",()=>shutdown("SIGTERM"));process.on("uncaughtException",e=>{log(`Uncaught exception: ${e.message}`);cleanupPidFile();process.exit(1)});(function main(){ensureDirs();if(checkExistingDaemon()){process.exit(0)}writePidFile();log("═══════════════════════════════════════════");log("Gemini Auto-Reviewer Daemon started");log(`PID: ${process.pid}`);log(`Project: ${PROJECT_ROOT}`);log(`Watching: ${PENDING_FILE}`);log(`Debounce: ${DEBOUNCE_MS}ms`);log(`Daily limit: ${DAILY_LIMIT}`);log("═══════════════════════════════════════════");const existingFiles=readPendingFiles();if(existingFiles.length>0){log(`Found ${existingFiles.length} existing pending file(s). Processing...`);onPendingFileChanged()}startWatcher();log("Daemon ready. Waiting for file changes...")})();